const ch = $input.first().json[0];
const post = $('loop-posts').item.json;
const now = new Date();
const [start, end] = (ch.posting_window || '00:00-23:59').split('-').map(t => parseInt(t.replace(':','')));
const curr = now.getHours() * 100 + now.getMinutes();
const in_window = curr >= start && curr < end;
return [{json: { in_window, curr_hour_minute: curr, window: ch.posting_window, platform: post.platform, post_id: post.id }}];

const post = $('loop-posts').item.json;
const ch = $('fetch-channel').item.json[0];
const [start_str] = (ch.posting_window || '00:00-23:59').split('-');
const [h, m] = start_str.split(':').map(Number);
const now = new Date();
const next_slot = new Date(now);
if (now.getHours() * 100 + now.getMinutes() >= h * 100 + m) {
  next_slot.setDate(next_slot.getDate() + 1);
}
next_slot.setHours(h, m, 0, 0);
const scheduled_ts = Math.floor(next_slot.getTime() / 1000);
return [{json: { post_id: post.id, scheduled_at_ts: scheduled_ts, action: 'requeue_next_window' }}];

const post = $('loop-posts').item.json;
const ch = $('fetch-channel').item.json[0];
const plt = post.platform.toLowerCase();
const body = post.body || '';
const token_ref = ch.oauth_token_ref || '';

let api_config = { endpoint: '', method: 'POST', headers: {}, body_obj: {} };

switch(plt) {
  case 'twitter':
    api_config.endpoint = 'https://api.twitter.com/2/tweets';
    api_config.headers = { 'Authorization': `Bearer ${token_ref}`, 'Content-Type': 'application/json' };
    api_config.body_obj = { text: body.slice(0, 280) };
    break;
  case 'mastodon':
    api_config.endpoint = (ch.api_endpoint || 'https://fosstodon.org') + '/api/v1/statuses';
    api_config.headers = { 'Authorization': `Bearer ${token_ref}`, 'Content-Type': 'application/json' };
    api_config.body_obj = { status: body.slice(0, 500), visibility: 'public' };
    break;
  case 'reddit':
    api_config.endpoint = 'https://oauth.reddit.com/api/submit';
    api_config.headers = { 'Authorization': `Bearer ${token_ref}`, 'Content-Type': 'application/x-www-form-urlencoded', 'User-Agent': 'AdOffBot/1.0' };
    api_config.body_form = { api_type: 'json', kind: 'self', sr: (post.body || '').match(/\/r\/([\w-]+)/)?.[1] || 'test', title: body.split('\\n')[0].slice(0, 300), text: body };
    api_config.use_form = true;
    break;
  case 'instagram':
    api_config.endpoint = `https://graph.facebook.com/v18.0/${ch.api_endpoint || 'IG_ID'}/media`;
    api_config.headers = { 'Content-Type': 'application/json' };
    api_config.body_obj = { image_url: 'PLACEHOLDER', caption: body.slice(0, 2200) };
    api_config.placeholder = true;
    break;
  case 'facebook':
    api_config.endpoint = `https://graph.facebook.com/v18.0/${ch.api_endpoint || 'PAGE_ID'}/feed`;
    api_config.headers = { 'Content-Type': 'application/json' };
    api_config.body_obj = { message: body.slice(0, 63206), access_token: token_ref };
    break;
  case 'tiktok':
    api_config.endpoint = 'https://open.tiktokapis.com/v2/post/publish/inbox/video/init/';
    api_config.headers = { 'Authorization': `Bearer ${token_ref}`, 'Content-Type': 'application/json' };
    api_config.body_obj = { source_info: { source: 'PULL_FROM_URL', video_url: 'PLACEHOLDER' }, post_info: { desc: body.slice(0, 2200) } };
    api_config.placeholder = true;
    break;
  case 'linkedin':
    api_config.endpoint = 'https://api.linkedin.com/v2/ugcPosts';
    api_config.headers = { 'Authorization': `Bearer ${token_ref}`, 'Content-Type': 'application/json', 'LinkedIn-Version': '202304' };
    api_config.body_obj = { author: 'PLACEHOLDER_URN', lifecycleState: 'PUBLISHED', specificContent: { 'com.linkedin.ugc.UGCPost': { content: { media: [], title: { text: body.slice(0, 200) }, description: { text: body.slice(0, 3000) } } } }, visibility: { 'com.linkedin.ugc.MemberNetworkVisibility': 'PUBLIC' } };
    api_config.placeholder = true;
    break;
  case 'bluesky':
    api_config.endpoint = 'https://bsky.social/xrpc/com.atproto.repo.createRecord';
    api_config.headers = { 'Authorization': `Bearer ${token_ref}`, 'Content-Type': 'application/json' };
    api_config.body_obj = { repo: $env.BLUESKY_DID || '', collection: 'app.bsky.feed.post', record: { text: body.slice(0, 300), createdAt: new Date().toISOString() } };
    api_config.placeholder = true;
    break;
  default:
    api_config.endpoint = 'https://api.example.com/unknown';
    api_config.error = `Unknown platform: ${plt}`;
}

return [{json: { api_config, post_id: post.id, platform: plt, has_token: !!token_ref, placeholder: api_config.placeholder || false }}];

const resp = $input.first().json || {};
const post = $('loop-posts').item.json;
const api = $('build-platform-body').item.json.api_config;
let success = false, post_id = '', error = '';

try {
  if (!resp.error && !resp.errors) {
    if (resp.data?.id) post_id = resp.data.id;
    else if (resp.id) post_id = resp.id;
    else if (resp.json?.data?.id) post_id = resp.json.data.id;
    success = !!post_id;
  } else {
    error = (resp.error || resp.errors?.[0]?.message || JSON.stringify(resp)).slice(0, 300);
  }
} catch(e) {
  error = e.message;
}

return [{json: { post_id: post.id, platform: post.platform, success, platform_post_id: post_id, error, response_status: resp.status || 'unknown' }}];

// Determine success + extract post URL from response
const orig = $('Load batch').first().json || {};
const resp = $input.first().json;
let posted_url = '';
let success = false;
let error = '';
try {
  if (resp.data?.id) { posted_url = 'https://twitter.com/i/status/' + resp.data.id; success = true; }
  else if (resp.id && resp.url) { posted_url = resp.url; success = true; }
  else if (resp.json?.data?.url) { posted_url = resp.json.data.url; success = true; }
  else if (resp.errors) { error = JSON.stringify(resp.errors).slice(0,300); }
  else if (resp.error) { error = String(resp.error).slice(0,300); }
  else { error = 'unknown response'; }
} catch(e) { error = e.message; }
return [{ json: { id: orig.id, success, posted_url, error, platform: orig.platform, account_id: orig.account_id }}];

